import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Despre Dotfiles | Dotfiles (RO)","titleTemplate":":title","description":"Descoperă prezentare tehnică a Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","frontmatter":{"title":"Despre Dotfiles | Dotfiles","description":"Descoperă prezentare tehnică a Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","lang":"ro-RO","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Despre Dotfiles | Previzualizare Dotfiles","canonical":"/ro/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Despre Dotfiles","pageType":"docs","schemaType":"WebPage","permalink":"/ro/about/"},"headers":[],"relativePath":"ro/about/index.md","filePath":"ro/about/index.md","lastUpdated":1773010926000}'),l={name:"ro/about/index.md"};function r(c,e,d,s,n,u){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="despre-dotfiles" tabindex="-1">Despre Dotfiles <a class="header-anchor" href="#despre-dotfiles" aria-label="Permalink to &quot;Despre Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 este o configurare shell cross-platform gestionată cu Chezmoi.</p><h2 id="instalare" tabindex="-1">Instalare <a class="header-anchor" href="#instalare" aria-label="Permalink to &quot;Instalare&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="verificare" tabindex="-1">Verificare <a class="header-anchor" href="#verificare" aria-label="Permalink to &quot;Verificare&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="comenzi-principale" tabindex="-1">Comenzi principale <a class="header-anchor" href="#comenzi-principale" aria-label="Permalink to &quot;Comenzi principale&quot;">​</a></h2><ul><li><code>dot apply</code> aplică modificările de configurare.</li><li><code>dot update</code> actualizează depozitul și preîncarcă cache-urile.</li><li><code>dot doctor</code> validează căile, instrumentele și starea shell-ului.</li><li><code>dot heal</code> repară starea lipsă sau deteriorată.</li><li><code>dot smoke-test</code> validează lanțurile de instrumente principale.</li></ul><h2 id="legaturi-conexe" tabindex="-1">Legături conexe <a class="header-anchor" href="#legaturi-conexe" aria-label="Permalink to &quot;Legături conexe&quot;">​</a></h2><ul><li><a href="/ro/aliases/">Aliasuri</a></li><li><a href="/ro/functions/">Funcții</a></li><li><a href="/ro/paths/">Căi</a></li></ul><h2 id="comenzi-principale-1" tabindex="-1">Comenzi principale <a class="header-anchor" href="#comenzi-principale-1" aria-label="Permalink to &quot;Comenzi principale&quot;">​</a></h2><p>CLI-ul <code>dot</code> oferă 53 de comenzi organizate pe categorii.</p><h3 id="nucleu" tabindex="-1">Nucleu <a class="header-anchor" href="#nucleu" aria-label="Permalink to &quot;Nucleu&quot;">​</a></h3><ul><li><code>dot apply</code> — aplică modificările de configurare.</li><li><code>dot sync</code> — obține starea cea mai recentă a depozitului și o aplică.</li><li><code>dot update</code> — actualizează depozitul și preîncălzește cache-urile.</li><li><code>dot add</code> — adaugă fișiere noi în sursa Chezmoi.</li><li><code>dot diff</code> — afișează modificările în așteptare înainte de aplicare.</li><li><code>dot status</code> — afișează starea fișierelor gestionate.</li><li><code>dot remove</code> — elimină un fișier din gestionare și șterge intrarea sursă.</li><li><code>dot cd</code> — deschide un shell în directorul sursă Chezmoi.</li><li><code>dot edit</code> — deschide un fișier gestionat în editorul tău.</li><li><code>dot clean-cache</code> — curăță cache-urile tranzitorii.</li><li><code>dot prewarm</code> — preîncarcă cache-urile pentru o pornire mai rapidă a shell-ului.</li></ul><h3 id="diagnostice" tabindex="-1">Diagnostice <a class="header-anchor" href="#diagnostice" aria-label="Permalink to &quot;Diagnostice&quot;">​</a></h3><ul><li><code>dot doctor</code> — validează căile, instrumentele și starea shell-ului.</li><li><code>dot heal</code> — repară automat starea lipsă sau defectă.</li><li><code>dot health</code> — execută o verificare de sănătate ușoară.</li><li><code>dot verify</code> — verifică integritatea fișierelor față de sursă.</li><li><code>dot scorecard</code> — afișează un scor de calitate a configurației.</li><li><code>dot snapshot</code> — capturează starea curentă pentru comparație ulterioară.</li><li><code>dot smoke-test</code> — validează lanțurile de instrumente principale complet.</li><li><code>dot chaos</code> — injectează defecte pentru a testa auto-repararea.</li><li><code>dot bundle</code> — exportă un pachet de configurare portabil.</li><li><code>dot rollback</code> — revine la un snapshot anterior.</li><li><code>dot drift</code> — detectează modificări neautorizate ale fișierelor gestionate.</li><li><code>dot history</code> — afișează jurnalul de istoric apply/sync.</li><li><code>dot benchmark</code> — măsoară timpul de pornire al shell-ului.</li><li><code>dot perf</code> — profilează inițializarea lentă a shell-ului.</li></ul><h3 id="aspect" tabindex="-1">Aspect <a class="header-anchor" href="#aspect" aria-label="Permalink to &quot;Aspect&quot;">​</a></h3><ul><li><code>dot theme</code> — schimbă schema de culori a terminalului.</li><li><code>dot wallpaper</code> — setează imaginea de fundal a desktopului (macOS).</li><li><code>dot fonts</code> — instalează sau actualizează Nerd Fonts.</li><li><code>dot tune</code> — ajustează densitatea interfeței și stilul promptului.</li></ul><h3 id="securitate" tabindex="-1">Securitate <a class="header-anchor" href="#securitate" aria-label="Permalink to &quot;Securitate&quot;">​</a></h3><ul><li><code>dot backup</code> — creează copii de rezervă criptate ale configurației.</li><li><code>dot encrypt-check</code> — verifică criptarea secretelor în repaus.</li><li><code>dot firewall</code> — configurează regulile firewall-ului gazdei.</li><li><code>dot telemetry</code> — controlează telemetria de utilizare anonimă.</li><li><code>dot dns-doh</code> — activează DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — blochează ecranul imediat.</li><li><code>dot usb-safety</code> — restricționează montarea automată a dispozitivelor USB de stocare.</li></ul><h3 id="secrete" tabindex="-1">Secrete <a class="header-anchor" href="#secrete" aria-label="Permalink to &quot;Secrete&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — inițializează backend-ul de secrete (age / GPG).</li><li><code>dot secrets</code> — listează intrările de secrete criptate.</li><li><code>dot secrets-create</code> — creează un nou secret criptat.</li><li><code>dot ssh-key</code> — generează sau rotește perechi de chei SSH.</li><li><code>dot ssh-cert</code> — solicită un certificat SSH de la o CA.</li></ul><h3 id="ia" tabindex="-1">IA <a class="header-anchor" href="#ia" aria-label="Permalink to &quot;IA&quot;">​</a></h3><ul><li><code>dot ai</code> — deschide o sesiune interactivă de asistent IA.</li><li><code>dot ai-setup</code> — configurează cheile API pentru furnizorii de IA.</li><li><code>dot ai-query</code> — trimite un prompt unic către un model de IA.</li><li>Wrapper-e de instrumente IA: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="instrumente" tabindex="-1">Instrumente <a class="header-anchor" href="#instrumente" aria-label="Permalink to &quot;Instrumente&quot;">​</a></h3><ul><li><code>dot tools</code> — listează înlocuitorii CLI incluși și starea lor.</li><li><code>dot new</code> — creează un nou fișier de alias sau funcție.</li><li><code>dot sandbox</code> — deschide un shell sandbox de unică folosință.</li><li><code>dot keys</code> — afișează combinațiile de taste curente.</li><li><code>dot learn</code> — pornește tutorialul interactiv.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — actualizează Dotfiles la cea mai recentă versiune.</li><li><code>dot packages</code> — listează pachetele instalate gestionate de Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — afișează informații despre versiune sau utilizare</li></ul>',28)])])}const f=i(l,[["render",r]]);export{h as __pageData,f as default};
